// R0: Classify Sender Result
// Reads Sender terminal output and determines whether HumanApproval may issue a retry token.
// Duplicate ownership and prior terminal/in-flight send states are not form-retryable.
const items = $input.all();
function norm(v) { return String(v == null ? "" : v).trim(); }
let approvalCtx = {};
try { approvalCtx = $("O1. Restore Reviewer Decision Context").first().json || {}; } catch {}
const NONRECOVERABLE_DETAILS = ["duplicate_send_guard", "send_key_conflict", "unsubscribe", "dnc", "legal", "safety_block"];
const NONRECOVERABLE_REASONS = ["SEND_OWNERSHIP_NOT_ACQUIRED", "SEND_LOCK_NOT_ACQUIRED", "PRIOR_TERMINAL_SEND_STATE_EXISTS", "DUPLICATE_SEND_GUARD", "SEND_ALREADY_TERMINAL"];
const NONRECOVERABLE_PRIOR_STATES = ["SENDING", "SENT", "SENT_RECONCILED", "SEND_UNCERTAIN", "PERMANENT_FAILURE", "AUTH_OR_PLAN_FAILURE", "INVALID_REPLY_TARGET", "RETRY_EXHAUSTED"];
return items.map(item => {
  const input = item.json || {};
  const rc = approvalCtx.review_case || {};
  const terminal = input.terminal || {};
  const blockDetails = Array.isArray(terminal.details) ? terminal.details : [];
  const failedGates = Array.isArray(terminal.failed_gate_ids) ? terminal.failed_gate_ids : [];
  const terminalReason = norm(terminal.reason || terminal.block_reason || terminal.terminal_reason);
  const priorState = norm(terminal.prior_state || terminal.priorState || terminal.prior_send_state);
  const isSent = terminal.result === "SENT" || terminal.send_state === "SENT" || terminal.terminal_status === "SENT" || terminal.terminal_status === "SENT_RECONCILED" || rc.status === "SENT" || rc.status === "SENT_RECONCILED";
  const isBlocked = !isSent && (terminal.result === "BLOCKED" || terminal.send_state === "BLOCKED" || terminal.terminal_status === "SEND_BLOCKED" || terminal.terminal_status === "SEND_BLOCKED_RETRYABLE");
  const hasNonrecoverableDetail = NONRECOVERABLE_DETAILS.some(d => blockDetails.includes(d));
  const hasNonrecoverableReason = NONRECOVERABLE_REASONS.includes(terminalReason);
  const hasNonrecoverablePriorState = NONRECOVERABLE_PRIOR_STATES.includes(priorState);
  const hasNonrecoverableGate = failedGates.includes("send_lock_acquired") || failedGates.includes("no_prior_terminal_send_state");
  const nonrecoverableReason = hasNonrecoverableReason ? terminalReason : (hasNonrecoverablePriorState ? "PRIOR_STATE_" + priorState : (hasNonrecoverableGate ? "NONRECOVERABLE_SEND_GATE" : null));
  const isRecoverable = isBlocked && !hasNonrecoverableDetail && !hasNonrecoverableReason && !hasNonrecoverablePriorState && !hasNonrecoverableGate;
  return { json: { ...input, review_case: rc, sender_block_classification: { is_blocked: isBlocked, is_sent: isSent, is_recoverable: isRecoverable, is_nonrecoverable: isBlocked && !isRecoverable, block_details: blockDetails, failed_gate_ids: failedGates, terminal_result: terminal.result || terminal.terminal_status || "UNKNOWN", terminal_reason: terminalReason || null, prior_state: priorState || null, nonrecoverable_reason: nonrecoverableReason, correction_instructions: isRecoverable ? "Return to the same review form, correct the listed block reason, then save before approving again. Do not use a new token unless the system explicitly issues a full production URL." : "No retry token was issued. If this was a duplicate submit or prior terminal send state, treat the original successful send as final and do not approve/send again.", case_status_before: rc.status || "UNKNOWN" } } };
});

// R-GenToken: Preserve existing review token for recoverable blocked-send retry
const items = $input.all();

return items.map(item => {
  const input  = item.json || {};
  const rc     = input.review_case || {};
  const config = input.config || {};

  const TTL_MINUTES = (config.review && config.review.review_token_ttl_minutes) || 60;
  const nowIso      = new Date().toISOString();
  const expiresIso  = new Date(Date.now() + TTL_MINUTES * 60000).toISOString();
  const preservedToken = String(rc.token || "");
  const base        = String((config.review || {}).review_base_url || "https://n8n.hmzaiautomation.com/webhook/reply-review").replace(/\/$/, "");
  const retryUrl    = base + "/review?case=" + encodeURIComponent(rc.case_id || "") + "&token=" + encodeURIComponent(preservedToken);

  return {
    json: {
      ...input,
      retry_token_context: {
        case_id:              rc.case_id || "",
        new_token:            preservedToken,
        new_token_expires_at: rc.token_expires_at || expiresIso,
        token_preserved:      true,
        retry_url:            retryUrl,
        issued_at:            nowIso,
        block_classification: input.sender_block_classification || {}
      }
    }
  };
});

